// backupos-pbs is the BackupOS PBS protocol service.
//
// Architecture:
//   - HTTPS server on port 8007 (configurable)
//   - Reads cert/key generated by the Node service
//   - Reads/writes the same SQLite database as the Node service
//   - Runs alongside backupos.service as a separate systemd unit
//
// Endpoints:
//   - GET  /api2/json/version    unauthenticated, 200 JSON
//   - any  /api2/json/backup     401 without valid auth; with auth: upgrade handshake → H2 streams
//   - GET  /api2/json/reader     inline auth; reader upgrade handshake → H2 streams (M5a)
//
// Over the H2 connection:
//   - POST /blob    write opaque blob atomically to snapshot directory (200)
//   - POST /finish  mark session finished + fsync snapshot dir (200)
//   - any other     501 stub (M4c-go-fixed-index, dynamic-index, chunk-upload follow)
package main

import (
	"context"
	"crypto/tls"
	"encoding/json"
	"errors"
	"flag"
	"log/slog"
	"net/http"
	"os"
	"os/signal"
	"strings"
	"syscall"
	"time"

	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/auth"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/internalauth"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/blob"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/jobsync"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/datastore"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/db"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/dynamicappend"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/dynamicchunk"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/dynamicclose"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/dynamicindex"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/finish"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/fixedappend"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/fixedchunk"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/fixedclose"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/fixedindex"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/previousarchive"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/previoustime"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/download"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/gcadmin"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/gcrun"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/gcsched"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/gctask"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/handlers"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/readchunk"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/readerupgrade"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/speedtest"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/datastorelist"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/datastorestatus"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/files"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/snapshotnotes"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/uploadbackuplog"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/selftest"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/session"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/sessionreaper"
	"github.com/dariusvorster/backupos/services/backupos-pbs/internal/upgrade"
)

// Build-time variables, set via -ldflags during go build.
var (
	versionString = "4.0.0"
	releaseString = "1"
	repoIDString  = "backupos"
)

func main() {
	var (
		bind     = flag.String("bind", "0.0.0.0:8007", "address:port to listen on")
		certPath = flag.String("cert", "/var/lib/backupos/pbs/cert.pem", "TLS certificate path")
		keyPath  = flag.String("key", "/var/lib/backupos/pbs/key.pem", "TLS private key path")
		dbPath   = flag.String("db", "/var/lib/backupos/backupos.db", "SQLite database path")
		pbsRoot  = flag.String("pbs-root", "/var/lib/backupos/pbs", "root directory for PBS datastore data (unused in this PR)")
	)
	flag.Parse()

	_ = pbsRoot // not used in this PR

	logger := slog.New(slog.NewJSONHandler(os.Stderr, &slog.HandlerOptions{
		Level: slog.LevelInfo,
	}))
	slog.SetDefault(logger)

	logger.Info("starting backupos-pbs",
		"version", versionString,
		"release", releaseString,
		"bind", *bind,
	)

	// Wire internal webhook for PBS → web alert delivery.
	internalURL := os.Getenv("BACKUPOS_INTERNAL_URL")
	internalSecret := os.Getenv("BACKUPOS_INTERNAL_SECRET")
	if internalURL == "" || internalSecret == "" {
		slog.Warn("BACKUPOS_INTERNAL_URL or BACKUPOS_INTERNAL_SECRET not set; PBS alerts will not fire")
	} else {
		jobsync.SetWebhookConfig(internalURL, internalSecret)
		slog.Info("internal webhook configured", "url", internalURL)
	}

	// Open the SQLite database (read+write, WAL mode handled by Node side).
	database, err := db.Open(*dbPath)
	if err != nil {
		logger.Error("failed to open database", "error", err, "path", *dbPath)
		os.Exit(1)
	}
	defer func() { _ = database.Close() }()
	logger.Info("database opened", "path", *dbPath)

	validator := auth.NewValidator(database)
	datastoreLookup := datastore.NewLookup(database)
	sessionStore := session.NewStore(database)
	upgradeHandler := upgrade.NewHandler(
		datastoreLookup,
		sessionStore,
		database,
		blob.NewHandler(),
		finish.NewHandler(sessionStore, database),
		fixedindex.NewHandler(),
		fixedchunk.NewHandler(),
		fixedappend.NewHandler(),
		fixedclose.NewHandler(),
		dynamicindex.NewHandler(),
		dynamicchunk.NewHandler(),
		dynamicappend.NewHandler(),
		dynamicclose.NewHandler(),
		previousarchive.NewHandler(nil),
		previoustime.NewHandler(),
		upgrade.StubStreamHandler(),
	)

	cert, err := tls.LoadX509KeyPair(*certPath, *keyPath)
	if err != nil {
		logger.Error("failed to load TLS cert", "error", err, "cert", *certPath, "key", *keyPath)
		os.Exit(1)
	}

	versionHandler := handlers.NewVersionHandler(handlers.VersionInfo{
		Version: versionString,
		Release: releaseString,
		RepoID:  repoIDString,
	})

	readerHandler := readerupgrade.NewHandler(
		validator,
		datastoreLookup,
		download.NewHandler(),
		readchunk.NewHandler(),
		speedtest.Handler(),
	)

	datastoreRoots := make(map[string]string)
	if allDS, err := datastoreLookup.All(); err != nil {
		logger.Warn("could not load datastores for GC tracker hydration", "error", err)
	} else {
		for _, ds := range allDS {
			datastoreRoots[ds.ID] = ds.Path
		}
	}
	gcTracker := gctask.NewTracker(gctask.FilePersister{}, datastoreRoots)
	oldestActiveWriter := gcrun.OldestActiveWriterFunc(func(ctx context.Context) (time.Time, error) {
		return sessionStore.OldestActiveStartedAt(ctx)
	})
	gcAdminHandler := gcadmin.NewHandler(datastoreLookup, gcTracker, oldestActiveWriter)
	gcScheduler := gcsched.New(datastoreLookup, gcTracker, oldestActiveWriter, 0)
	selfTestHandler        := selftest.NewHandler(database, datastoreLookup, versionString)
	datastoreListHandler   := datastorelist.NewHandler(database)
	datastoreStatusHandler := datastorestatus.NewHandler(datastoreLookup)
	filesHandler           := files.NewHandler(datastoreLookup)
	notesHandler           := snapshotnotes.NewHandler(datastoreLookup, database)
	uploadLogHandler       := uploadbackuplog.NewHandler(datastoreLookup)

	mux := http.NewServeMux()
	mux.HandleFunc("/api2/json/version", versionHandler.ServeHTTP)
	mux.HandleFunc("/api2/json/backup", requireAuth(validator, upgradeHandler.ServeHTTP))
	mux.HandleFunc("/api2/json/reader", readerHandler.ServeHTTP)
	// Route precedence note:
	//   /api2/json/admin/datastore     → exact match, list endpoint (PVE enumeration)
	//   /api2/json/admin/datastore/    → subtree match, per-datastore subroutes
	// Go's net/http mux serves the more specific exact match first, so the
	// list endpoint wins for the bare path and the subtree handles everything
	// from /api2/json/admin/datastore/<name>/... onward.
	mux.HandleFunc("/api2/json/admin/datastore", requireAuth(validator,
		func(w http.ResponseWriter, r *http.Request) {
			datastoreListHandler.ServeHTTP(w, r)
		},
	))
	mux.HandleFunc("/api2/json/admin/datastore/", requireAuth(validator,
		func(w http.ResponseWriter, r *http.Request) {
			switch {
			case strings.HasSuffix(r.URL.Path, "/gc"):
				gcAdminHandler.ServeHTTP(w, r)
			case strings.HasSuffix(r.URL.Path, "/status"):
				datastoreStatusHandler.ServeHTTP(w, r)
			case strings.HasSuffix(r.URL.Path, "/files"):
				filesHandler.ServeHTTP(w, r)
			case strings.HasSuffix(r.URL.Path, "/notes"):
				notesHandler.ServeHTTP(w, r)
			case strings.HasSuffix(r.URL.Path, "/upload-backup-log"):
				uploadLogHandler.ServeHTTP(w, r)
			default:
				slog.Info("404 (admin/datastore subtree)",
					"method", r.Method,
					"path",   r.URL.Path,
					"query",  r.URL.RawQuery,
					"remote", r.RemoteAddr,
				)
				http.NotFound(w, r)
			}
		},
	))
	mux.HandleFunc("/api2/json/admin/self-test/datastore/", selfTestHandler.ServeHTTP)

	// Internal-only routes, gated by BACKUPOS_INTERNAL_SECRET (no PBS token required).
	// Used by the web UI for stats sync and manual GC trigger.
	//
	//   GET  /api2/internal/datastore/<store>/status  → datastoreStatusHandler
	//   POST /api2/internal/datastore/<store>/gc      → gcAdminHandler (start GC)
	//   GET  /api2/internal/datastore/<store>/gc      → gcAdminHandler (last status)
	//
	// Path is rewritten from /api2/internal/... to /api2/json/admin/... before
	// forwarding so the underlying handlers' path parsing works unchanged.
	mux.Handle("/api2/internal/datastore/", internalauth.Middleware(internalSecret,
		http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			r.URL.Path = strings.Replace(r.URL.Path, "/api2/internal/datastore/", "/api2/json/admin/datastore/", 1)
			switch {
			case strings.HasSuffix(r.URL.Path, "/gc"):
				gcAdminHandler.ServeHTTP(w, r)
			case strings.HasSuffix(r.URL.Path, "/status"):
				datastoreStatusHandler.ServeHTTP(w, r)
			default:
				http.NotFound(w, r)
			}
		}),
	))

	mux.HandleFunc("/", notFound)

	// serverCtx is cancelled on SIGINT/SIGTERM so background goroutines
	// (reaper, future cron jobs) stop cleanly alongside the HTTP server.
	serverCtx, serverCancel := context.WithCancel(context.Background())
	defer serverCancel()

	reaper := sessionreaper.New(database, 0, 0)
	go reaper.Run(serverCtx)
	go gcScheduler.Run(serverCtx)

	server := &http.Server{
		Addr:    *bind,
		Handler: normalizeLeadingSlashes(mux),
		TLSConfig: &tls.Config{
			Certificates: []tls.Certificate{cert},
			MinVersion:   tls.VersionTLS12,
			// HTTP/2 ALPN deliberately disabled. PBS protocol uses HTTP/1.1
			// with Upgrade: proxmox-backup-protocol-v1 — not h2c, not h2 ALPN.
			// The upgrade handler lands in M4b-go-upgrade.
			NextProtos: []string{"http/1.1"},
		},
		ReadHeaderTimeout: 10 * time.Second,
	}

	go func() {
		sigCh := make(chan os.Signal, 1)
		signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)
		sig := <-sigCh
		logger.Info("received signal, shutting down", "signal", sig)
		serverCancel() // stop background goroutines
		ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
		defer cancel()
		if err := server.Shutdown(ctx); err != nil {
			logger.Error("graceful shutdown failed", "error", err)
		}
	}()

	logger.Info("listening", "bind", *bind)
	err = server.ListenAndServeTLS("", "")
	if err != nil && !errors.Is(err, http.ErrServerClosed) {
		logger.Error("server failed", "error", err)
		os.Exit(1)
	}
	logger.Info("backupos-pbs stopped")
}

// requireAuth wraps a handler with PBS token authentication.
//
// If the Authorization header is missing or invalid, returns 401.
// If the token is valid, attaches the Identity to the request context
// (via auth.WithIdentity) and calls the wrapped handler.
func requireAuth(v *auth.Validator, next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		authHeader := r.Header.Get("Authorization")
		if authHeader == "" {
			writeAuthError(w, r, "missing Authorization header")
			return
		}

		parsed, err := auth.ParseAuthHeader(authHeader)
		if err != nil {
			prefix := authHeader
			if len(prefix) > 30 {
				prefix = prefix[:30] + "..."
			}
			slog.Info("auth header rejected",
				"prefix", prefix,
				"method", r.Method,
				"path",   r.URL.Path,
				"remote", r.RemoteAddr,
			)
			if cookie := r.Header.Get("Cookie"); cookie != "" {
				cookiePrefix := cookie
				if len(cookiePrefix) > 60 {
					cookiePrefix = cookiePrefix[:60] + "..."
				}
				slog.Info("cookie present alongside rejected auth",
					"cookie_prefix", cookiePrefix,
					"path", r.URL.Path,
				)
			}
			writeAuthError(w, r, "malformed Authorization header")
			return
		}

		identity, err := v.Validate(parsed)
		if err != nil {
			// Log the actual error for diagnostics, but return a generic
			// 401 to the caller. We don't want to leak whether the
			// token exists or just had a wrong secret.
			slog.Info("auth failed",
				"reason", err.Error(),
				"user", parsed.User,
				"realm", parsed.Realm,
				"token_name", parsed.TokenName,
				"remote", r.RemoteAddr,
			)
			writeAuthError(w, r, "invalid credentials")
			return
		}

		slog.Info("auth ok",
			"token_id", identity.TokenID,
			"user", identity.User,
			"realm", identity.Realm,
			"token_name", identity.TokenName,
			"path", r.URL.Path,
			"method", r.Method,
		)

		ctx := auth.WithIdentity(r.Context(), identity)
		next(w, r.WithContext(ctx))
	}
}

func writeAuthError(w http.ResponseWriter, r *http.Request, reason string) {
	slog.Info("401",
		"reason", reason,
		"method", r.Method,
		"path",   r.URL.Path,
		"query",  r.URL.RawQuery,
		"remote", r.RemoteAddr,
	)
	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("WWW-Authenticate", `PBSAPIToken realm="backupos"`)
	w.WriteHeader(http.StatusUnauthorized)
	resp := map[string]string{"error": reason}
	_ = json.NewEncoder(w).Encode(resp)
}

// normalizeLeadingSlashes collapses runs of leading slashes in r.URL.Path
// to a single slash before dispatching. proxmox-backup-client 4.1.5
// constructs upgrade URLs as "//api2/json/backup?..." (a known quirk in
// its build_uri helper). Without this normalisation, Go's net/http.ServeMux
// 307-redirects to the canonical "/api2/json/backup" form and the client
// — which does not follow redirects on the upgrade endpoint — bails with
// the redirect HTML body as its error message.
func normalizeLeadingSlashes(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if len(r.URL.Path) >= 2 && r.URL.Path[0] == '/' && r.URL.Path[1] == '/' {
			// Collapse leading run of '/' to a single '/'.
			i := 0
			for i < len(r.URL.Path) && r.URL.Path[i] == '/' {
				i++
			}
			cleaned := "/" + r.URL.Path[i:]
			slog.Info("normalised duplicate leading slashes",
				"original_path", r.URL.Path,
				"cleaned_path",  cleaned,
				"method",        r.Method,
				"remote",        r.RemoteAddr,
			)
			r.URL.Path = cleaned
			r.URL.RawPath = "" // force re-encode on read
		}
		next.ServeHTTP(w, r)
	})
}

func notFound(w http.ResponseWriter, r *http.Request) {
	slog.Info("404",
		"method", r.Method,
		"path",   r.URL.Path,
		"query",  r.URL.RawQuery,
		"remote", r.RemoteAddr,
	)
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusNotFound)
	resp := map[string]string{"error": "not found"}
	_ = json.NewEncoder(w).Encode(resp)
}
